"use client";

import { useState, useRef } from "react";
import { Upload, X, Loader2, CheckCircle2, AlertCircle } from "lucide-react";

interface FileUploadProps {
  onUpload: (url: string) => void;
  defaultValue?: string;
  label?: string;
  accept?: string;
}

export default function FileUpload({ onUpload, defaultValue, label, accept = "image/*" }: FileUploadProps) {
  const [uploading, setUploading] = useState(false);
  const [preview, setPreview] = useState(defaultValue || "");
  const [error, setError] = useState("");
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Local preview
    const reader = new FileReader();
    reader.onloadend = () => {
      setPreview(reader.result as string);
    };
    reader.readAsDataURL(file);

    setUploading(true);
    setError("");

    try {
      const formData = new FormData();
      formData.append("file", file);

      const response = await fetch("/api/upload", {
        method: "POST",
        body: formData,
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || "Upload failed");
      }

      onUpload(data.url);
      setPreview(data.url);
    } catch (err: any) {
      setError(err.message);
      setPreview(defaultValue || "");
    } finally {
      setUploading(false);
    }
  };

  const handleClear = (e: React.MouseEvent) => {
    e.stopPropagation();
    setPreview("");
    onUpload("");
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
  };

  return (
    <div className="space-y-3">
      {label && <label className="block text-xs font-black text-slate-400 uppercase tracking-widest ml-1">{label}</label>}
      
      <div 
        onClick={() => fileInputRef.current?.click()}
        className={`relative group cursor-pointer border-2 border-dashed rounded-2xl transition-all h-32 flex flex-col items-center justify-center p-4 overflow-hidden
          ${uploading ? 'border-primary/50 bg-primary/5' : 'border-slate-200 hover:border-primary/50 hover:bg-slate-50'}
          ${preview ? 'border-solid border-slate-100 bg-white' : ''}
          ${error ? 'border-red-200 bg-red-50' : ''}
        `}
      >
        <input 
          type="file" 
          ref={fileInputRef}
          onChange={handleFileChange}
          accept={accept}
          className="hidden" 
        />

        {uploading ? (
          <div className="flex flex-col items-center animate-pulse">
            <Loader2 className="w-8 h-8 animate-spin text-primary mb-2" />
            <span className="text-[10px] font-bold text-primary uppercase tracking-tighter">Uploading...</span>
          </div>
        ) : preview ? (
          <div className="absolute inset-0 w-full h-full flex items-center justify-center bg-slate-50/50">
             {/* eslint-disable-next-line @next/next/no-img-element */}
            <img 
              src={preview} 
              alt="Preview" 
              className="max-w-full max-h-full object-contain p-2"
            />
            <div className="absolute inset-0 bg-slate-900/0 group-hover:bg-slate-900/40 transition-all flex items-center justify-center">
               <div className="opacity-0 group-hover:opacity-100 transition-all scale-90 group-hover:scale-100 flex gap-2">
                  <button 
                    type="button"
                    className="p-2 bg-white rounded-xl shadow-lg hover:scale-110 active:scale-95 transition-all"
                  >
                    <Upload className="w-4 h-4 text-slate-900" />
                  </button>
                  <button 
                    type="button"
                    onClick={handleClear}
                    className="p-2 bg-white rounded-xl shadow-lg hover:scale-110 active:scale-95 transition-all"
                  >
                    <X className="w-4 h-4 text-red-500" />
                  </button>
               </div>
            </div>
          </div>
        ) : (
          <div className="flex flex-col items-center text-slate-400 group-hover:text-primary transition-colors">
            <Upload className="w-8 h-8 mb-2 opacity-20 group-hover:opacity-100 transition-all" />
            <span className="text-[10px] font-black uppercase tracking-widest">Click to upload image</span>
          </div>
        )}

        {error && (
          <div className="absolute bottom-2 left-0 right-0 flex justify-center">
             <div className="px-3 py-1 bg-red-500 text-white rounded-full text-[8px] font-black uppercase flex items-center gap-1 shadow-lg shadow-red-500/20">
                <AlertCircle className="w-3 h-3" />
                {error}
             </div>
          </div>
        )}

        {!uploading && !error && preview && (
           <div className="absolute top-2 right-2 flex justify-center">
              <div className="p-1 bg-green-500 text-white rounded-full shadow-lg shadow-green-500/20">
                 <CheckCircle2 className="w-3 h-3" />
              </div>
           </div>
        )}
      </div>
    </div>
  );
}
